// PERSONNALISEZ ces constantes pour votre marque (elles pilotent toute la veille).
const THEMES = [
  'Theme de veille 1 (ex. : votre secteur d\'activite)',
  'Theme de veille 2 (ex. : les outils de vos personas)',
  'Theme de veille 3 (ex. : reglementation de votre marche)'
];
const AUDIENCE = 'Description courte de votre audience cible (ex. : dirigeants de PME industrielles en France)';
const FENETRE_HEURES = 192; // 8 jours

const requete = `Realise une veille sur les ${FENETRE_HEURES} dernieres heures concernant : ${THEMES.join(' ; ')}.\nAudience visee : ${AUDIENCE}.\n\nInclue : articles de medias et blogs specialises, discussions significatives sur les reseaux, annonces d'outils ou d'etudes pertinentes.\n\nPour chaque element, fournis :\n- Titre\n- Description de 2-3 lignes\n- Lien source\n- Indicateur de traction (engagement, tendance)\n\nLimite-toi aux contenus publies dans la fenetre demandee. Retourne 8-15 elements pertinents, en francais.`;

return [{ json: { requete, themes: THEMES, audience: AUDIENCE } }];

const resultat = $input.first().json;
const contenuVeille = resultat.choices?.[0]?.message?.content || '';
const citations = Array.isArray(resultat.citations) ? resultat.citations : [];

if (!contenuVeille) throw new Error('Recherche veille vide — verifier le credential et le quota de l'API de recherche');

const themes = $('Construire requête veille').first().json.themes;
const audience = $('Construire requête veille').first().json.audience;

const prompt = `Tu es le responsable editorial d'une marque. Voici les resultats d'une veille hebdomadaire.

Audience cible : ${audience}
Themes suivis : ${themes.join(' ; ')}

Pour chaque sujet exploitable en contenu marketing, retourne un objet JSON. Reponds UNIQUEMENT avec un tableau JSON valide :
[{
  "sujet": "titre du sujet de contenu propose",
  "angle": "angle editorial en 1-2 phrases",
  "plateforme": "LinkedIn | Blog | Newsletter",
  "score": note de 1 a 10 (pertinence pour l'audience),
  "priorite": "Chaud | Tendance | Fond",
  "sources": "URLs des sources"
}]

Sois exigeant sur le score : 7+ = reellement exploitable cette semaine.

RESULTATS DE VEILLE :
${contenuVeille}

CITATIONS :
${citations.join('\n')}`;

return [{ json: { prompt } }];

const response = $input.first().json;
const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '[]';

let propositions;
try {
  propositions = JSON.parse(text);
  if (!Array.isArray(propositions)) propositions = [propositions];
} catch (e) {
  return []; // la branche 'aucune proposition' prend le relais
}

const retenues = propositions.filter(p => (p.score || 0) >= 7);

return retenues.map(p => ({
  json: {
    date: new Date().toISOString().split('T')[0],
    sujet: (p.sujet || '').toString(),
    angle: (p.angle || '').toString(),
    plateforme: (p.plateforme || 'LinkedIn').toString(),
    score: String(p.score || 0),
    priorite: (p.priorite || 'Tendance').toString(),
    sources: (p.sources || '').toString(),
    statut: 'PROPOSITION'
  }
}));

const response = $input.first().json;
const text = response.candidates?.[0]?.content?.parts?.[0]?.text || '[]';

let propositions;
try {
  propositions = JSON.parse(text);
  if (!Array.isArray(propositions)) propositions = [propositions];
} catch (e) {
  return [{ json: { aucuneProposition: true, message: 'Impossible de parser la reponse LLM' } }];
}

const retenues = propositions.filter(p => (p.score || 0) >= 7);
if (retenues.length === 0) {
  return [{ json: { aucuneProposition: true } }];
}
return [];

const items = $input.all().map(i => i.json);
const date = new Date().toISOString().split('T')[0];
const nomFichier = `${date}--veille--hebdo.md`;

const corps = items.map(p => `## ${p.sujet}

- **Angle** : ${p.angle}
- **Plateforme** : ${p.plateforme}
- **Score** : ${p.score}/10 — ${p.priorite}
- **Sources** : ${p.sources}
`).join('
');

const contenu = `---
type: veille
source: veille-hebdo-automatique
date: ${date}
classification: veille
statut: a-trier
---

# Veille hebdo — ${date}

${items.length} proposition(s) de sujet (score >= 7/10).

${corps}`;

return [{ json: { contenu, nomFichier, nb: items.length, propositions: items } }];
